/* =====================================================================
   Drag & Drop engine (pointer-based — works with mouse + touch)
   ===================================================================== */
const DnD = createContext(null);

function DnDProvider({ children }) {
  const [active, setActive] = useState(false);
  const info = useRef(null);
  const ghostRef = useRef(null);
  const [ghost, setGhost] = useState(null);
  const zones = useRef({});

  const registerZone = (id, onDrop) => { zones.current[id] = onDrop; };
  const unregisterZone = (id) => { delete zones.current[id]; };

  const place = (x, y) => {
    const g = ghostRef.current;
    if (!g || !info.current) return;
    g.style.left = x - info.current.ox + "px";
    g.style.top = y - info.current.oy + "px";
  };

  const startDrag = (i) => {
    info.current = i;
    setGhost(i.content);
    setActive(true);
    requestAnimationFrame(() => place(i.sx, i.sy));
  };

  useEffect(() => {
    if (!active) return;
    const move = (e) => place(e.clientX, e.clientY);
    const up = (e) => {
      const g = ghostRef.current;
      if (g) g.style.display = "none";
      const el = document.elementFromPoint(e.clientX, e.clientY);
      if (g) g.style.display = "";
      let node = el, zid = null;
      while (node) {
        if (node.dataset && node.dataset.dropzone) { zid = node.dataset.dropzone; break; }
        node = node.parentElement;
      }
      const di = info.current;
      info.current = null;
      setActive(false);
      if (zid && zones.current[zid]) zones.current[zid](di.id, di.payload, zid);
    };
    window.addEventListener("pointermove", move);
    window.addEventListener("pointerup", up);
    window.addEventListener("pointercancel", up);
    return () => {
      window.removeEventListener("pointermove", move);
      window.removeEventListener("pointerup", up);
      window.removeEventListener("pointercancel", up);
    };
  }, [active]);

  return (
    <DnD.Provider value={{ startDrag, registerZone, unregisterZone }}>
      {children}
      {active && (
        <div ref={ghostRef} style={{
          position: "fixed", zIndex: 9999, pointerEvents: "none",
          width: info.current ? info.current.w : "auto", opacity: .95,
          transform: "scale(1.06)", filter: "drop-shadow(0 6px 10px rgba(0,0,0,.25))"
        }}>{ghost}</div>
      )}
    </DnD.Provider>
  );
}

function Draggable({ id, payload, disabled, children, wrapWidth }) {
  const { startDrag } = useContext(DnD);
  const ref = useRef();
  const down = (e) => {
    if (disabled) return;
    e.preventDefault();
    const r = ref.current.getBoundingClientRect();
    startDrag({
      id, payload, sx: e.clientX, sy: e.clientY,
      ox: e.clientX - r.left, oy: e.clientY - r.top,
      w: r.width,
      content: <div style={{ width: wrapWidth || r.width }}>{children}</div>,
    });
  };
  return (
    <div ref={ref} onPointerDown={down}
      style={{ touchAction: "none", cursor: disabled ? "default" : "grab", opacity: disabled ? .45 : 1 }}>
      {children}
    </div>
  );
}

function DropZone({ id, onDrop, children, style }) {
  const { registerZone, unregisterZone } = useContext(DnD);
  useEffect(() => { registerZone(id, onDrop); return () => unregisterZone(id); });
  return <div data-dropzone={id} style={style}>{children}</div>;
}

