/* ---------- feedback toast ---------- */
function useFeedback() {
  const [fb, setFb] = useState(null);
  const show = (text, ok = true) => {
    setFb({ text, ok, key: Date.now() });
    setTimeout(() => setFb(f => (f && f.text === text ? null : f)), 1600);
  };
  const node = fb ? (
    <div key={fb.key} style={{
      position: "absolute", top: 92, insetInlineStart: "50%", transform: "translateX(-50%)",
      background: fb.ok ? AMIT.green : "#e07a5f", color: "#fff",
      padding: "8px 20px", borderRadius: 22, fontWeight: 800, fontSize: 16,
      zIndex: 50, animation: "popIn .3s ease both", boxShadow: "0 4px 12px rgba(0,0,0,.2)"
    }}>{fb.text}</div>
  ) : null;
  return [node, show];
}

/* ---------- sound ---------- */
function useSound(muted) {
  const ctxRef = useRef(null);
  return (ok) => {
    if (muted) return;
    try {
      if (!ctxRef.current) ctxRef.current = new (window.AudioContext || window.webkitAudioContext)();
      const c = ctxRef.current, o = c.createOscillator(), g = c.createGain();
      o.connect(g); g.connect(c.destination);
      o.frequency.value = ok ? 660 : 200;
      o.type = ok ? "sine" : "triangle";
      g.gain.setValueAtTime(.001, c.currentTime);
      g.gain.exponentialRampToValueAtTime(.12, c.currentTime + .02);
      g.gain.exponentialRampToValueAtTime(.001, c.currentTime + .25);
      o.start(); o.stop(c.currentTime + .26);
      if (ok) { const o2 = c.createOscillator(); o2.connect(g); o2.frequency.setValueAtTime(880, c.currentTime + .1); o2.start(c.currentTime + .1); o2.stop(c.currentTime + .26); }
    } catch (e) { /* ignore */ }
  };
}

