/* =====================================================================
   PART A — Creation (reaction + property comparison)
   ===================================================================== */
function CreationScreen({ cfg, onDone, done, award, showFb, sound }) {
  const [reacted, setReacted] = useState(done);
  const [flash, setFlash] = useState(false);
  const [cells, setCells] = useState({}); // cellId -> value
  const [erred, setErred] = useState(false);
  const [shakeCell, setShakeCell] = useState(null);
  const [rewarded, setRewarded] = useState(done);

  const react = () => {
    setFlash(true); sound(true);
    setTimeout(() => setFlash(false), 700);
    setReacted(true);
    showFb("תגובה החלה! ✨", true);
  };

  const allCellsRight = cfg.cells.every(c => cells[c.id] === c.answer);

  useEffect(() => {
    if (reacted && allCellsRight && !rewarded) {
      setRewarded(true);
      award(!erred);
      showFb(erred ? "מדויק! +50" : "מצוין! +100", true);
      onDone();
    }
  }, [reacted, cells]); // eslint-disable-line

  return (
    <Card>
      <ScreenTitle sub={reacted ? "עכשיו גררו את התכונות הנכונות של התוצר אל הטבלה." : "גררו את מקור החום אל חומרי הגלם כדי להתחיל את התגובה."}>
        {cfg.title}
      </ScreenTitle>

      {/* reaction stage */}
      <DropZone id={`react-${cfg.id}`} onDrop={() => { if (!reacted) react(); }}
        style={{
          position: "relative", background: reacted ? "#20303f" : "#f2f6fb", borderRadius: 16,
          padding: "20px 12px", display: "flex", alignItems: "center", justifyContent: "center",
          gap: 46, minHeight: 260, transition: "background .5s", overflow: "hidden"
        }}>
        {flash && <div style={{ position: "absolute", inset: 0, background: cfg.flashColor, animation: "flash .7s ease" }} />}
        {!reacted ? (
          <>
            <Pile label={cfg.a.label} sym={cfg.a.sym} color={cfg.a.color} />
            <span style={{ fontSize: 38, color: AMIT.midBlue, fontWeight: 800 }}>+</span>
            <Pile label={cfg.b.label} sym={cfg.b.sym} color={cfg.b.color} />
          </>
        ) : (
          <div style={{ textAlign: "center", animation: "popIn .5s ease both" }}>
            <div style={{
              width: 150, height: 150, borderRadius: 24, background: cfg.product.color,
              display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 12px",
              color: cfg.product.text || "#fff", fontWeight: 800, fontSize: 34, boxShadow: "0 4px 12px rgba(0,0,0,.35)"
            }}>{cfg.product.sym}</div>
            <div style={{ color: "#fff", fontWeight: 800, fontSize: 20 }}>{cfg.product.label}</div>
          </div>
        )}
      </DropZone>

      {/* fire chip */}
      {!reacted && (
        <div style={{ display: "flex", justifyContent: "center", marginTop: 16 }}>
          <Draggable id="fire" payload="fire">
            <div style={{
              display: "flex", alignItems: "center", gap: 8, background: "#fff",
              border: `2px solid #e0662a`, borderRadius: 16, padding: "10px 18px",
              boxShadow: "0 3px 8px rgba(224,102,42,.3)", fontWeight: 800, color: "#c9531f"
            }}>
              <Flame color="#e0662a" size={26} /> מקור חום
            </div>
          </Draggable>
        </div>
      )}

      {/* comparison table */}
      {reacted && (
        <div className="fadeUp" style={{ marginTop: 16 }}>
          <div style={{ display: "grid", gridTemplateColumns: "auto 1fr 1fr", gap: 8, alignItems: "center" }}>
            <Th></Th><Th>חומרי הגלם</Th><Th>התוצר</Th>
            {cfg.cells.map(c => (
              <React.Fragment key={c.id}>
                <RowLabel>{c.prop}</RowLabel>
                <ReadCell>{c.rawText}</ReadCell>
                <DropZone id={`cell-${cfg.id}-${c.id}`} onDrop={(id, val) => {
                  if (val === c.answer) { setCells(s => ({ ...s, [c.id]: val })); sound(true); }
                  else { setErred(true); sound(false); setShakeCell(c.id); showFb("לא מדויק, נסו תכונה אחרת", false); setTimeout(() => setShakeCell(null), 500); }
                }} style={{
                  minHeight: 46, borderRadius: 12, background: cells[c.id] ? "#eef7f0" : "#f4f8fc",
                  border: `2px solid ${cells[c.id] ? AMIT.green : "#dbe5ef"}`,
                  display: "flex", alignItems: "center", justifyContent: "center", padding: 6,
                  fontWeight: 700, color: AMIT.darkGreen,
                  animation: shakeCell === c.id ? "shake .5s" : "none"
                }}>{cells[c.id] || <span style={{ color: "#9fb0c0", fontSize: 22 }}>?</span>}</DropZone>
              </React.Fragment>
            ))}
          </div>

          {!allCellsRight && (
            <div style={{ display: "flex", gap: 10, flexWrap: "wrap", justifyContent: "center", marginTop: 16 }}>
              {cfg.tags.map(t => (
                <Draggable key={t} id={t} payload={t}><Tag text={t} /></Draggable>
              ))}
            </div>
          )}
          {allCellsRight && <DoneBadge text={`התכונות השתנו לגמרי! ל־${cfg.product.label} תכונות חדשות, שונות מהיסודות שיצרו אותו.`} />}
        </div>
      )}
    </Card>
  );
}
function Pile({ label, sym, color }) {
  return (
    <div style={{ textAlign: "center" }}>
      <div style={{ width: 132, height: 132, borderRadius: 22, background: color, display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontWeight: 800, fontSize: 34, boxShadow: "inset -4px -4px 8px rgba(0,0,0,.2)" }}>{sym}</div>
      <div style={{ marginTop: 10, fontWeight: 700, color: AMIT.darkBlue, fontSize: 18 }}>{label}</div>
    </div>
  );
}
const Th = ({ children }) => <div style={{ fontWeight: 800, color: AMIT.midBlue, fontSize: 13, textAlign: "center", paddingBottom: 2 }}>{children}</div>;
const RowLabel = ({ children }) => <div style={{ fontWeight: 800, color: AMIT.darkBlue, fontSize: 14 }}>{children}</div>;
const ReadCell = ({ children }) => <div style={{ minHeight: 46, borderRadius: 12, background: "#f4f8fc", display: "flex", alignItems: "center", justifyContent: "center", padding: 6, color: "#5b7085", fontWeight: 600, fontSize: 13, textAlign: "center" }}>{children}</div>;

/* =====================================================================
   PART B — Decomposition
   ===================================================================== */
function DecompScreen({ cfg, onDone, done, award, showFb, sound }) {
  const [triggered, setTriggered] = useState(done);
  const [anim, setAnim] = useState(false);
  const [rewarded, setRewarded] = useState(done);

  const go = () => {
    setAnim(true); sound(true);
    setTimeout(() => { setTriggered(true); }, 650);
    if (!rewarded) { setRewarded(true); award(true); onDone(); }
  };

  return (
    <Card>
      <ScreenTitle sub={cfg.instruction}>{cfg.title}</ScreenTitle>

      <DropZone id={`dec-${cfg.id}`} onDrop={() => { if (!triggered) go(); }}
        style={{
          position: "relative", background: "#eef4fb", borderRadius: 16, minHeight: 190,
          padding: 16, display: "flex", alignItems: "flex-end", justifyContent: "center", gap: 24, overflow: "hidden"
        }}>
        {cfg.render(triggered, anim)}
      </DropZone>

      {!triggered ? (
        <div style={{ display: "flex", justifyContent: "center", marginTop: 16 }}>
          <Draggable id={cfg.tool.id} payload={cfg.tool.id}>
            <div style={{
              display: "flex", alignItems: "center", gap: 8, background: "#fff",
              border: `2px solid ${cfg.tool.border}`, borderRadius: 16, padding: "10px 18px",
              boxShadow: `0 3px 8px ${cfg.tool.border}44`, fontWeight: 800, color: cfg.tool.border
            }}>
              {cfg.tool.icon} {cfg.tool.label}
            </div>
          </Draggable>
        </div>
      ) : (
        <DoneBadge text={cfg.doneText} />
      )}
    </Card>
  );
}

