/* =====================================================================
   PART C — Atom counting
   ===================================================================== */
function shuffle(a) { const x = [...a]; for (let i = x.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [x[i], x[j]] = [x[j], x[i]]; } return x; }

function AtomCountScreen({ formulas, onDone, done, award, showFb, sound }) {
  const [idx, setIdx] = useState(0);
  const f = formulas[idx];

  return (
    <Card>
      <ScreenTitle sub="גררו את המספר הנכון לכל תיבה: כמה אטומים מכל סוג, וכמה בסך הכל.">
        פענוח נוסחאות — ספירת אטומים
      </ScreenTitle>
      <div style={{ display: "flex", gap: 6, marginBottom: 12 }}>
        {formulas.map((ff, i) => (
          <div key={i} style={{ flex: 1, height: 6, borderRadius: 4, background: i < idx ? AMIT.green : i === idx ? AMIT.accent : "#dbe5ef" }} />
        ))}
      </div>

      <FormulaCounter key={idx} f={f} sound={sound} showFb={showFb}
        onSolved={(clean) => {
          award(clean);
          if (idx + 1 < formulas.length) {
            showFb(clean ? "מדויק! +100" : "יפה! +50", true);
            setTimeout(() => setIdx(idx + 1), 700);
          } else {
            showFb(clean ? "מצוין! +100" : "יפה! +50", true);
            onDone();
          }
        }} />
    </Card>
  );
}

function FormulaCounter({ f, onSolved, sound, showFb }) {
  const [vals, setVals] = useState({});
  const [erred, setErred] = useState(false);
  const [shake, setShake] = useState(null);
  const [solved, setSolved] = useState(false);
  const bank = useRef(shuffle(f.bank)).current;

  const boxes = [...f.elements.map(e => ({ id: e.el, label: e.label, sym: e.el, answer: e.count })),
  { id: "__total", label: 'סה"כ אטומים', sym: "Σ", answer: f.total }];

  const drop = (boxId, answer) => (dragId, val) => {
    if (val === answer) {
      const nv = { ...vals, [boxId]: val };
      setVals(nv); sound(true);
      if (boxes.every(b => nv[b.id] === b.answer) && !solved) {
        setSolved(true);
        onSolved(!erred);
      }
    } else {
      setErred(true); sound(false); setShake(boxId);
      showFb("כמעט! ספרו שוב את האטומים", false);
      setTimeout(() => setShake(null), 500);
    }
  };

  return (
    <div>
      {/* formula + model */}
      <div style={{ background: "#f2f6fb", borderRadius: 14, padding: "14px 12px", textAlign: "center" }}>
        <div style={{ fontSize: 60, fontWeight: 800, color: AMIT.darkBlue, letterSpacing: 1, direction: "ltr" }}>{f.display}</div>
        <div style={{ display: "flex", flexWrap: "wrap", justifyContent: "center", marginTop: 10, direction: "ltr" }}>
          {f.model.map((el, i) => <AtomBall key={i} el={el} />)}
        </div>
      </div>

      {/* boxes */}
      <div style={{ display: "flex", gap: 10, flexWrap: "wrap", justifyContent: "center", marginTop: 14 }}>
        {boxes.map(b => (
          <div key={b.id} style={{ textAlign: "center" }}>
            <div style={{ fontSize: 16, fontWeight: 700, color: AMIT.midBlue, marginBottom: 6 }}>
              {b.id === "__total" ? b.label : <>{b.label} <span style={{ direction: "ltr" }}>({b.sym})</span></>}
            </div>
            <DropZone id={`box-${f.key}-${b.id}`} onDrop={drop(b.id, b.answer)} style={{
              width: 94, height: 86, borderRadius: 16,
              background: vals[b.id] != null ? "#eef7f0" : "#fff",
              border: `2px solid ${vals[b.id] != null ? AMIT.green : (b.id === "__total" ? AMIT.accent : "#cdd9e6")}`,
              display: "flex", alignItems: "center", justifyContent: "center",
              fontSize: 40, fontWeight: 800, color: AMIT.darkBlue,
              animation: shake === b.id ? "shake .5s" : "none"
            }}>{vals[b.id] != null ? vals[b.id] : <span style={{ color: "#b9c6d4" }}>?</span>}</DropZone>
          </div>
        ))}
      </div>

      {/* number bank */}
      {!solved ? (
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", justifyContent: "center", marginTop: 16 }}>
          {bank.map((n, i) => (
            <Draggable key={i} id={"n" + i} payload={n}><NumberChip value={n} /></Draggable>
          ))}
        </div>
      ) : (
        <DoneBadge text={`נכון! בנוסחה ${f.name} יש בסך הכול ${f.total} אטומים.`} />
      )}
    </div>
  );
}

/* =====================================================================
   PART D — Balancing + conservation of mass
   ===================================================================== */
function BalanceScreen({ cfg, onDone, done, award, showFb, sound }) {
  const [coef, setCoef] = useState({}); // id -> number
  const [erred, setErred] = useState(false);
  const [shake, setShake] = useState(null);
  const [solved, setSolved] = useState(false);
  const bank = useRef(shuffle(cfg.bank)).current;

  const sumSide = (terms, el) => terms.reduce((s, t) => s + (coef[t.id] || 0) * (t.atoms[el] || 0), 0);
  const mass = (terms) => terms.reduce((s, t) => s + (coef[t.id] || 0) * t.mass, 0);
  const elements = [...new Set([...cfg.left, ...cfg.right].flatMap(t => Object.keys(t.atoms)))];
  const allFilled = [...cfg.left, ...cfg.right].every(t => coef[t.id] > 0);
  const balanced = allFilled && elements.every(el => sumSide(cfg.left, el) === sumSide(cfg.right, el));
  const massL = mass(cfg.left), massR = mass(cfg.right);
  const tilt = balanced ? 0 : Math.max(-11, Math.min(11, (massR - massL) * 0.5 + (massR > massL ? 3 : massR < massL ? -3 : 0)));

  useEffect(() => {
    if (balanced && !solved) {
      setSolved(true); sound(true);
      award(!erred);
      showFb(erred ? "מאוזן! +50" : "מאוזן בול! +100", true);
      onDone();
    }
  }, [coef]); // eslint-disable-line

  const putCoef = (id) => (dragId, val) => {
    setCoef(c => ({ ...c, [id]: val }));
    sound(true);
    const next = { ...coef, [id]: val };
    const stillBad = elements.some(el =>
      cfg.left.reduce((s, t) => s + (next[t.id] || 0) * (t.atoms[el] || 0), 0) !==
      cfg.right.reduce((s, t) => s + (next[t.id] || 0) * (t.atoms[el] || 0), 0));
    if (stillBad && [...cfg.left, ...cfg.right].every(t => next[t.id] > 0)) { setErred(true); }
  };

  const Molecule = ({ t, first }) => (
    <span style={{ display: "inline-flex", alignItems: "center", gap: 4 }}>
      {!first && <span style={{ fontSize: 22, color: AMIT.midBlue, fontWeight: 800, margin: "0 2px" }}>+</span>}
      <DropZone id={`c-${cfg.id}-${t.id}`} onDrop={putCoef(t.id)} style={{
        width: 60, height: 66, borderRadius: 14, background: coef[t.id] ? "#eef7f0" : "#fff",
        border: `2px solid ${coef[t.id] ? AMIT.green : AMIT.accent}`,
        display: "inline-flex", alignItems: "center", justifyContent: "center",
        fontSize: 22, fontWeight: 800, color: AMIT.darkBlue,
        animation: shake === t.id ? "shake .5s" : "none"
      }}>{coef[t.id] || <span style={{ color: "#c2cedb", fontSize: 18 }}>?</span>}</DropZone>
      <span style={{ fontSize: 42, fontWeight: 800, color: AMIT.darkBlue, direction: "ltr" }}>{t.f}</span>
    </span>
  );

  return (
    <Card>
      <ScreenTitle sub="גררו מקדמים (מספרים) לפני המולקולות. כשמספר האטומים שווה בשני הצדדים — המאזניים מתיישרים.">
        {cfg.title}
      </ScreenTitle>

      {/* scale */}
      <div style={{ background: "#eef4fb", borderRadius: 16, padding: "8px 10px 14px", overflow: "hidden" }}>
        <div style={{ position: "relative", height: 210, maxWidth: 680, margin: "0 auto" }}>
          <div style={{ position: "absolute", insetInlineStart: "50%", top: 8, transform: "translateX(-50%)", width: 11, height: 132, background: "#7c8ca0", borderRadius: 6 }} />
          <div style={{ position: "absolute", insetInlineStart: "50%", top: 6, transform: `translateX(-50%) rotate(${tilt}deg)`, transformOrigin: "center", transition: "transform .6s ease", width: 440, height: 9 }}>
            <div style={{ position: "absolute", inset: 0, background: "#5b6b7f", borderRadius: 4 }} />
            <Pan side="start" terms={cfg.left} coef={coef} />
            <Pan side="end" terms={cfg.right} coef={coef} />
          </div>
          <div style={{ position: "absolute", insetInlineStart: "50%", bottom: 0, transform: "translateX(-50%)", width: 70, height: 12, background: "#7c8ca0", borderRadius: 6 }} />
        </div>
        <div style={{ textAlign: "center", fontWeight: 800, color: balanced ? AMIT.green : "#b06a4a", fontSize: 14 }}>
          {balanced ? "⚖️ מאוזן — חוק שימור המסה מתקיים!" : allFilled ? "⚖️ עדיין לא מאוזן — כמות האטומים שונה בין הצדדים" : "מלאו את כל המקדמים"}
        </div>
      </div>

      {/* equation */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8, flexWrap: "wrap", marginTop: 16, direction: "rtl" }}>
        <span style={{ display: "inline-flex", alignItems: "center", gap: 6 }}>
          {cfg.left.map((t, i) => <Molecule key={t.id} t={t} first={i === 0} />)}
        </span>
        <span style={{ fontSize: 36, color: AMIT.midBlue, fontWeight: 800, direction: "ltr" }}>→</span>
        <span style={{ display: "inline-flex", alignItems: "center", gap: 6 }}>
          {cfg.right.map((t, i) => <Molecule key={t.id} t={t} first={i === 0} />)}
        </span>
      </div>

      {!solved ? (
        <div style={{ display: "flex", gap: 8, justifyContent: "center", marginTop: 18 }}>
          {bank.map((n, i) => <Draggable key={i} id={"b" + i} payload={n}><NumberChip value={n} big /></Draggable>)}
        </div>
      ) : (
        <DoneBadge text="התגובה מאוזנת! מספר האטומים של כל יסוד זהה לפני התגובה ואחריה — שום אטום לא נעלם ולא נוצר." />
      )}
    </Card>
  );
}
function Pan({ side, terms, coef }) {
  const balls = terms.flatMap(t => Array((coef[t.id] || 0)).fill(t.f));
  return (
    <div style={{ position: "absolute", top: 0, [side === "start" ? "insetInlineStart" : "insetInlineEnd"]: -6 }}>
      <div style={{ width: 3, height: 42, background: "#5b6b7f", margin: "0 auto" }} />
      <div style={{ minWidth: 160, minHeight: 60, background: "#cbd6e2", borderRadius: "0 0 60px 60px", border: "2px solid #9fb0c1", padding: "8px 10px", display: "flex", flexWrap: "wrap", gap: 2, justifyContent: "center", alignItems: "center" }}>
        {balls.length === 0 && <span style={{ color: "#8fa0b2", fontSize: 11 }}>—</span>}
        {balls.map((b, i) => (
          <span key={i} style={{ fontSize: 10, fontWeight: 800, color: AMIT.darkBlue, background: "#fff", borderRadius: 6, padding: "1px 4px", direction: "ltr" }}>{b}</span>
        ))}
      </div>
    </div>
  );
}

