      <button onClick={onRestart} style={{
        marginTop: 22, background: "#fff", color: AMIT.midBlue, border: `2px solid ${AMIT.midBlue}`,
        borderRadius: 26, padding: "12px 32px", fontSize: 17, fontWeight: 800, cursor: "pointer",
        display: "inline-flex", alignItems: "center", gap: 8
      }}>
        <RotateCcw size={20} /> להתחיל מחדש
      </button>
