/* =====================================================================
   MAIN APP
   ===================================================================== */
const TOTAL = 9;

export default function App() {
  const [screen, setScreen] = useState(0); // 0 intro, 1..9, 10 summary
  const [score, setScore] = useState(0);
  const [streak, setStreak] = useState(0);
  const [maxStreak, setMaxStreak] = useState(0);
  const [completed, setCompleted] = useState({});
  const [muted, setMuted] = useState(false);
  const [fbNode, showFb] = useFeedback();
  const sound = useSound(muted);

  const award = (clean) => {
    setScore(s => s + (clean ? 100 : 50));
    if (clean) setStreak(st => { const n = st + 1; setMaxStreak(m => Math.max(m, n)); return n; });
    else setStreak(0);
  };
  const markDone = (idx) => setCompleted(c => ({ ...c, [idx]: true }));

  const restart = () => { setScreen(0); setScore(0); setStreak(0); setMaxStreak(0); setCompleted({}); };

  const baseBg = "#e8f1f9";

  const renderActivity = () => {
    const p = { onDone: () => markDone(screen), done: !!completed[screen], award, showFb, sound };
    switch (screen) {
      case 1: return <CreationScreen cfg={CREATION_1} {...p} />;
      case 2: return <CreationScreen cfg={CREATION_2} {...p} />;
      case 3: return <DecompScreen cfg={DECOMP_WATER} {...p} />;
      case 4: return <DecompScreen cfg={DECOMP_SUGAR} {...p} />;
      case 5: return <AtomCountScreen formulas={FORMULAS.a} {...p} />;
      case 6: return <AtomCountScreen formulas={FORMULAS.b} {...p} />;
      case 7: return <AtomCountScreen formulas={FORMULAS.c} {...p} />;
      case 8: return <BalanceScreen cfg={BALANCE_WATER} {...p} />;
      case 9: return <BalanceScreen cfg={BALANCE_MGO} {...p} />;
      default: return null;
    }
  };

  return (
    <DnDProvider>
      <div className="amit-root" dir="rtl" style={{ minHeight: "100vh", background: baseBg, paddingBottom: 20, position: "relative" }}>
        <GlobalStyles />
        <div style={{ position: "fixed", inset: 0, zIndex: 0, backgroundImage: `url(${ASSETS.bg})`, backgroundSize: "cover", backgroundPosition: "center" }} />
        <div style={{ position: "fixed", inset: 0, zIndex: 0, background: "linear-gradient(180deg, rgba(240,247,252,.58), rgba(228,240,250,.72))" }} />
        <div style={{ position: "relative", zIndex: 1 }}>

        {screen === 0 && <Intro onStart={() => setScreen(1)} />}

        {screen >= 1 && screen <= TOTAL && (
          <>
            <HUD score={score} streak={streak} step={Object.keys(completed).filter(k => k >= 1 && k <= TOTAL).length} total={TOTAL}
              muted={muted} setMuted={setMuted} onHome={() => setScreen(0)} />
            <div style={{ position: "relative", maxWidth: 1040, margin: "0 auto" }}>
              {fbNode}
              {renderActivity()}
              <NavBar
                backEnabled={screen > 1}
                onBack={() => setScreen(s => Math.max(1, s - 1))}
                nextEnabled={!!completed[screen]}
                onNext={() => setScreen(s => s + 1)}
              />
            </div>
          </>
        )}

        {screen > TOTAL && <Summary score={score} streak={maxStreak} onRestart={restart} />}
        </div>
      </div>
    </DnDProvider>
  );
}
